1	use crate::session::{ContentBlock, ConversationMessage, MessageRole, Session};
2	
3	const COMPACT_CONTINUATION_PREAMBLE: &str =
4	    "This session is being continued from a previous conversation that ran out of context. The summary below covers the earlier portion of the conversation.\n\n";
5	const COMPACT_RECENT_MESSAGES_NOTE: &str = "Recent messages are preserved verbatim.";
6	const COMPACT_DIRECT_RESUME_INSTRUCTION: &str = "Continue the conversation from where it left off without asking the user any further questions. Resume directly вАФ do not acknowledge the summary, do not recap what was happening, and do not preface with continuation text.";
7	
8	/// Thresholds controlling when and how a session is compacted.
9	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
10	pub struct CompactionConfig {
11	    pub preserve_recent_messages: usize,
12	    pub max_estimated_tokens: usize,
13	}
14	
15	impl Default for CompactionConfig {
16	    fn default() -> Self {
17	        Self {
18	            preserve_recent_messages: 4,
19	            max_estimated_tokens: 10_000,
20	        }
21	    }
22	}
23	
24	/// Result of compacting a session into a summary plus preserved tail messages.
25	#[derive(Debug, Clone, PartialEq, Eq)]
26	pub struct CompactionResult {
27	    pub summary: String,
28	    pub formatted_summary: String,
29	    pub compacted_session: Session,
30	    pub removed_message_count: usize,
31	}
32	
33	/// Roughly estimates the token footprint of the current session transcript.
34	#[must_use]
35	pub fn estimate_session_tokens(session: &Session) -> usize {
36	    session.messages.iter().map(estimate_message_tokens).sum()
37	}
38	
39	/// Returns `true` when the session exceeds the configured compaction budget.
40	#[must_use]
41	pub fn should_compact(session: &Session, config: CompactionConfig) -> bool {
42	    let start = compacted_summary_prefix_len(session);
43	    let compactable = &session.messages[start..];
44	
45	    compactable.len() > config.preserve_recent_messages
46	        && compactable
47	            .iter()
48	            .map(estimate_message_tokens)
49	            .sum::<usize>()
50	            >= config.max_estimated_tokens
51	}
52	
53	/// Normalizes a compaction summary into user-facing continuation text.
54	#[must_use]
55	pub fn format_compact_summary(summary: &str) -> String {
56	    let without_analysis = strip_tag_block(summary, "analysis");
57	    let formatted = if let Some(content) = extract_tag_block(&without_analysis, "summary") {
58	        without_analysis.replace(
59	            &format!("<summary>{content}</summary>"),
60	            &format!("Summary:\n{}", content.trim()),
61	        )
62	    } else {
63	        without_analysis
64	    };
65	
66	    collapse_blank_lines(&formatted).trim().to_string()
67	}
68	
69	/// Builds the synthetic system message used after session compaction.
70	#[must_use]
71	pub fn get_compact_continuation_message(
72	    summary: &str,
73	    suppress_follow_up_questions: bool,
74	    recent_messages_preserved: bool,
75	) -> String {
76	    let mut base = format!(
77	        "{COMPACT_CONTINUATION_PREAMBLE}{}",
78	        format_compact_summary(summary)
79	    );
80	
81	    if recent_messages_preserved {
82	        base.push_str("\n\n");
83	        base.push_str(COMPACT_RECENT_MESSAGES_NOTE);
84	    }
85	
86	    if suppress_follow_up_questions {
87	        base.push('\n');
88	        base.push_str(COMPACT_DIRECT_RESUME_INSTRUCTION);
89	    }
90	
91	    base
92	}
