94	/// Compacts a session by summarizing older messages and preserving the recent tail.
95	#[must_use]
96	pub fn compact_session(session: &Session, config: CompactionConfig) -> CompactionResult {
97	    if !should_compact(session, config) {
98	        return CompactionResult {
99	            summary: String::new(),
100	            formatted_summary: String::new(),
101	            compacted_session: session.clone(),
102	            removed_message_count: 0,
103	        };
104	    }
105	
106	    let existing_summary = session
107	        .messages
108	        .first()
109	        .and_then(extract_existing_compacted_summary);
110	    let compacted_prefix_len = usize::from(existing_summary.is_some());
111	    let keep_from = session
112	        .messages
113	        .len()
114	        .saturating_sub(config.preserve_recent_messages);
115	    let removed = &session.messages[compacted_prefix_len..keep_from];
116	    let preserved = session.messages[keep_from..].to_vec();
117	    let summary =
118	        merge_compact_summaries(existing_summary.as_deref(), &summarize_messages(removed));
119	    let formatted_summary = format_compact_summary(&summary);
120	    let continuation = get_compact_continuation_message(&summary, true, !preserved.is_empty());
121	
122	    let mut compacted_messages = vec![ConversationMessage {
123	        role: MessageRole::System,
124	        blocks: vec![ContentBlock::Text { text: continuation }],
125	        usage: None,
126	    }];
127	    compacted_messages.extend(preserved);
128	
129	    let mut compacted_session = session.clone();
130	    compacted_session.messages = compacted_messages;
131	    compacted_session.record_compaction(summary.clone(), removed.len());
132	
133	    CompactionResult {
134	        summary,
135	        formatted_summary,
136	        compacted_session,
137	        removed_message_count: removed.len(),
138	    }
139	}
