151	fn summarize_messages(messages: &[ConversationMessage]) -> String {
152	    let user_messages = messages
153	        .iter()
154	        .filter(|message| message.role == MessageRole::User)
155	        .count();
156	    let assistant_messages = messages
157	        .iter()
158	        .filter(|message| message.role == MessageRole::Assistant)
159	        .count();
160	    let tool_messages = messages
161	        .iter()
162	        .filter(|message| message.role == MessageRole::Tool)
163	        .count();
164	
165	    let mut tool_names = messages
166	        .iter()
167	        .flat_map(|message| message.blocks.iter())
168	        .filter_map(|block| match block {
169	            ContentBlock::ToolUse { name, .. } => Some(name.as_str()),
170	            ContentBlock::ToolResult { tool_name, .. } => Some(tool_name.as_str()),
171	            ContentBlock::Text { .. } => None,
172	        })
173	        .collect::<Vec<_>>();
174	    tool_names.sort_unstable();
175	    tool_names.dedup();
176	
177	    let mut lines = vec![
178	        "<summary>".to_string(),
179	        "Conversation summary:".to_string(),
180	        format!(
181	            "- Scope: {} earlier messages compacted (user={}, assistant={}, tool={}).",
182	            messages.len(),
183	            user_messages,
184	            assistant_messages,
185	            tool_messages
186	        ),
187	    ];
188	
189	    if !tool_names.is_empty() {
190	        lines.push(format!("- Tools mentioned: {}.", tool_names.join(", ")));
191	    }
192	
193	    let recent_user_requests = collect_recent_role_summaries(messages, MessageRole::User, 3);
194	    if !recent_user_requests.is_empty() {
195	        lines.push("- Recent user requests:".to_string());
196	        lines.extend(
197	            recent_user_requests
198	                .into_iter()
199	                .map(|request| format!("  - {request}")),
200	        );
201	    }
202	
203	    let pending_work = infer_pending_work(messages);
204	    if !pending_work.is_empty() {
205	        lines.push("- Pending work:".to_string());
206	        lines.extend(pending_work.into_iter().map(|item| format!("  - {item}")));
207	    }
208	
209	    let key_files = collect_key_files(messages);
210	    if !key_files.is_empty() {
211	        lines.push(format!("- Key files referenced: {}.", key_files.join(", ")));
212	    }
213	
214	    if let Some(current_work) = infer_current_work(messages) {
215	        lines.push(format!("- Current work: {current_work}"));
216	    }
217	
218	    lines.push("- Key timeline:".to_string());
219	    for message in messages {
220	        let role = match message.role {
221	            MessageRole::System => "system",
222	            MessageRole::User => "user",
223	            MessageRole::Assistant => "assistant",
224	            MessageRole::Tool => "tool",
225	        };
226	        let content = message
227	            .blocks
228	            .iter()
229	            .map(summarize_block)
230	            .collect::<Vec<_>>()
231	            .join(" | ");
232	        lines.push(format!("  - {role}: {content}"));
233	    }
234	    lines.push("</summary>".to_string());
235	    lines.join("\n")
236	}
