238	fn merge_compact_summaries(existing_summary: Option<&str>, new_summary: &str) -> String {
239	    let Some(existing_summary) = existing_summary else {
240	        return new_summary.to_string();
241	    };
242	
243	    let previous_highlights = extract_summary_highlights(existing_summary);
244	    let new_formatted_summary = format_compact_summary(new_summary);
245	    let new_highlights = extract_summary_highlights(&new_formatted_summary);
246	    let new_timeline = extract_summary_timeline(&new_formatted_summary);
247	
248	    let mut lines = vec!["<summary>".to_string(), "Conversation summary:".to_string()];
249	
250	    if !previous_highlights.is_empty() {
251	        lines.push("- Previously compacted context:".to_string());
252	        lines.extend(
253	            previous_highlights
254	                .into_iter()
255	                .map(|line| format!("  {line}")),
256	        );
257	    }
258	
259	    if !new_highlights.is_empty() {
260	        lines.push("- Newly compacted context:".to_string());
261	        lines.extend(new_highlights.into_iter().map(|line| format!("  {line}")));
262	    }
263	
264	    if !new_timeline.is_empty() {
265	        lines.push("- Key timeline:".to_string());
266	        lines.extend(new_timeline.into_iter().map(|line| format!("  {line}")));
267	    }
268	
269	    lines.push("</summary>".to_string());
270	    lines.join("\n")
271	}
