273	fn summarize_block(block: &ContentBlock) -> String {
274	    let raw = match block {
275	        ContentBlock::Text { text } => text.clone(),
276	        ContentBlock::ToolUse { name, input, .. } => format!("tool_use {name}({input})"),
277	        ContentBlock::ToolResult {
278	            tool_name,
279	            output,
280	            is_error,
281	            ..
282	        } => format!(
283	            "tool_result {tool_name}: {}{output}",
284	            if *is_error { "error " } else { "" }
285	        ),
286	    };
287	    truncate_summary(&raw, 160)
288	}
289	
290	fn collect_recent_role_summaries(
291	    messages: &[ConversationMessage],
292	    role: MessageRole,
293	    limit: usize,
294	) -> Vec<String> {
295	    messages
296	        .iter()
297	        .filter(|message| message.role == role)
298	        .rev()
299	        .filter_map(|message| first_text_block(message))
300	        .take(limit)
301	        .map(|text| truncate_summary(text, 160))
302	        .collect::<Vec<_>>()
303	        .into_iter()
304	        .rev()
305	        .collect()
306	}
307	
308	fn infer_pending_work(messages: &[ConversationMessage]) -> Vec<String> {
309	    messages
310	        .iter()
311	        .rev()
312	        .filter_map(first_text_block)
313	        .filter(|text| {
314	            let lowered = text.to_ascii_lowercase();
315	            lowered.contains("todo")
316	                || lowered.contains("next")
317	                || lowered.contains("pending")
318	                || lowered.contains("follow up")
319	                || lowered.contains("remaining")
320	        })
321	        .take(3)
322	        .map(|text| truncate_summary(text, 160))
323	        .collect::<Vec<_>>()
324	        .into_iter()
325	        .rev()
326	        .collect()
327	}
