329	fn collect_key_files(messages: &[ConversationMessage]) -> Vec<String> {
330	    let mut files = messages
331	        .iter()
332	        .flat_map(|message| message.blocks.iter())
333	        .map(|block| match block {
334	            ContentBlock::Text { text } => text.as_str(),
335	            ContentBlock::ToolUse { input, .. } => input.as_str(),
336	            ContentBlock::ToolResult { output, .. } => output.as_str(),
337	        })
338	        .flat_map(extract_file_candidates)
339	        .collect::<Vec<_>>();
340	    files.sort();
341	    files.dedup();
342	    files.into_iter().take(8).collect()
343	}
344	
345	fn infer_current_work(messages: &[ConversationMessage]) -> Option<String> {
346	    messages
347	        .iter()
348	        .rev()
349	        .filter_map(first_text_block)
350	        .find(|text| !text.trim().is_empty())
351	        .map(|text| truncate_summary(text, 200))
352	}
353	
354	fn first_text_block(message: &ConversationMessage) -> Option<&str> {
355	    message.blocks.iter().find_map(|block| match block {
356	        ContentBlock::Text { text } if !text.trim().is_empty() => Some(text.as_str()),
357	        ContentBlock::ToolUse { .. }
358	        | ContentBlock::ToolResult { .. }
359	        | ContentBlock::Text { .. } => None,
360	    })
361	}
362	
363	fn has_interesting_extension(candidate: &str) -> bool {
364	    std::path::Path::new(candidate)
365	        .extension()
366	        .and_then(|extension| extension.to_str())
367	        .is_some_and(|extension| {
368	            ["rs", "ts", "tsx", "js", "json", "md"]
369	                .iter()
370	                .any(|expected| extension.eq_ignore_ascii_case(expected))
371	        })
372	}
373	
374	fn extract_file_candidates(content: &str) -> Vec<String> {
375	    content
376	        .split_whitespace()
377	        .filter_map(|token| {
378	            let candidate = token.trim_matches(|char: char| {
379	                matches!(char, ',' | '.' | ':' | ';' | ')' | '(' | '"' | '\'' | '`')
380	            });
381	            if candidate.contains('/') && has_interesting_extension(candidate) {
382	                Some(candidate.to_string())
383	            } else {
384	                None
385	            }
386	        })
387	        .collect()
388	}
389	
390	fn truncate_summary(content: &str, max_chars: usize) -> String {
391	    if content.chars().count() <= max_chars {
392	        return content.to_string();
393	    }
394	    let mut truncated = content.chars().take(max_chars).collect::<String>();
395	    truncated.push('вА¶');
396	    truncated
397	}
398	
399	fn estimate_message_tokens(message: &ConversationMessage) -> usize {
400	    message
401	        .blocks
402	        .iter()
403	        .map(|block| match block {
404	            ContentBlock::Text { text } => text.len() / 4 + 1,
405	            ContentBlock::ToolUse { name, input, .. } => (name.len() + input.len()) / 4 + 1,
406	            ContentBlock::ToolResult {
407	                tool_name, output, ..
408	            } => (tool_name.len() + output.len()) / 4 + 1,
409	        })
410	        .sum()
411	}
