413	fn extract_tag_block(content: &str, tag: &str) -> Option<String> {
414	    let start = format!("<{tag}>");
415	    let end = format!("</{tag}>");
416	    let start_index = content.find(&start)? + start.len();
417	    let end_index = content[start_index..].find(&end)? + start_index;
418	    Some(content[start_index..end_index].to_string())
419	}
420	
421	fn strip_tag_block(content: &str, tag: &str) -> String {
422	    let start = format!("<{tag}>");
423	    let end = format!("</{tag}>");
424	    if let (Some(start_index), Some(end_index_rel)) = (content.find(&start), content.find(&end)) {
425	        let end_index = end_index_rel + end.len();
426	        let mut stripped = String::new();
427	        stripped.push_str(&content[..start_index]);
428	        stripped.push_str(&content[end_index..]);
429	        stripped
430	    } else {
431	        content.to_string()
432	    }
433	}
434	
435	fn collapse_blank_lines(content: &str) -> String {
436	    let mut result = String::new();
437	    let mut last_blank = false;
438	    for line in content.lines() {
439	        let is_blank = line.trim().is_empty();
440	        if is_blank && last_blank {
441	            continue;
442	        }
443	        result.push_str(line);
444	        result.push('\n');
445	        last_blank = is_blank;
446	    }
447	    result
448	}
449	
450	fn extract_existing_compacted_summary(message: &ConversationMessage) -> Option<String> {
451	    if message.role != MessageRole::System {
452	        return None;
453	    }
454	
455	    let text = first_text_block(message)?;
456	    let summary = text.strip_prefix(COMPACT_CONTINUATION_PREAMBLE)?;
457	    let summary = summary
458	        .split_once(&format!("\n\n{COMPACT_RECENT_MESSAGES_NOTE}"))
459	        .map_or(summary, |(value, _)| value);
460	    let summary = summary
461	        .split_once(&format!("\n{COMPACT_DIRECT_RESUME_INSTRUCTION}"))
462	        .map_or(summary, |(value, _)| value);
463	    Some(summary.trim().to_string())
464	}
465	
466	fn extract_summary_highlights(summary: &str) -> Vec<String> {
467	    let mut lines = Vec::new();
468	    let mut in_timeline = false;
469	
470	    for line in format_compact_summary(summary).lines() {
471	        let trimmed = line.trim_end();
472	        if trimmed.is_empty() || trimmed == "Summary:" || trimmed == "Conversation summary:" {
473	            continue;
474	        }
475	        if trimmed == "- Key timeline:" {
476	            in_timeline = true;
477	            continue;
478	        }
479	        if in_timeline {
480	            continue;
481	        }
482	        lines.push(trimmed.to_string());
483	    }
484	
485	    lines
486	}
487	
488	fn extract_summary_timeline(summary: &str) -> Vec<String> {
489	    let mut lines = Vec::new();
490	    let mut in_timeline = false;
491	
492	    for line in format_compact_summary(summary).lines() {
493	        let trimmed = line.trim_end();
494	        if trimmed == "- Key timeline:" {
495	            in_timeline = true;
496	            continue;
497	        }
498	        if !in_timeline {
499	            continue;
500	        }
501	        if trimmed.is_empty() {
502	            break;
503	        }
504	        lines.push(trimmed.to_string());
505	    }
506	
507	    lines
508	}
