510	#[cfg(test)]
511	mod tests {
512	    use super::{
513	        collect_key_files, compact_session, estimate_session_tokens, format_compact_summary,
514	        get_compact_continuation_message, infer_pending_work, should_compact, CompactionConfig,
515	    };
516	    use crate::session::{ContentBlock, ConversationMessage, MessageRole, Session};
517	
518	    #[test]
519	    fn formats_compact_summary_like_upstream() {
520	        let summary = "<analysis>scratch</analysis>\n<summary>Kept work</summary>";
521	        assert_eq!(format_compact_summary(summary), "Summary:\nKept work");
522	    }
523	
524	    #[test]
525	    fn leaves_small_sessions_unchanged() {
526	        let mut session = Session::new();
527	        session.messages = vec![ConversationMessage::user_text("hello")];
528	
529	        let result = compact_session(&session, CompactionConfig::default());
530	        assert_eq!(result.removed_message_count, 0);
531	        assert_eq!(result.compacted_session, session);
532	        assert!(result.summary.is_empty());
533	        assert!(result.formatted_summary.is_empty());
534	    }
