536	    #[test]
537	    fn compacts_older_messages_into_a_system_summary() {
538	        let mut session = Session::new();
539	        session.messages = vec![
540	            ConversationMessage::user_text("one ".repeat(200)),
541	            ConversationMessage::assistant(vec![ContentBlock::Text {
542	                text: "two ".repeat(200),
543	            }]),
544	            ConversationMessage::tool_result("1", "bash", "ok ".repeat(200), false),
545	            ConversationMessage {
546	                role: MessageRole::Assistant,
547	                blocks: vec![ContentBlock::Text {
548	                    text: "recent".to_string(),
549	                }],
550	                usage: None,
551	            },
552	        ];
553	
554	        let result = compact_session(
555	            &session,
556	            CompactionConfig {
557	                preserve_recent_messages: 2,
558	                max_estimated_tokens: 1,
559	            },
560	        );
561	
562	        assert_eq!(result.removed_message_count, 2);
563	        assert_eq!(
564	            result.compacted_session.messages[0].role,
565	            MessageRole::System
566	        );
567	        assert!(matches!(
568	            &result.compacted_session.messages[0].blocks[0],
569	            ContentBlock::Text { text } if text.contains("Summary:")
570	        ));
571	        assert!(result.formatted_summary.contains("Scope:"));
572	        assert!(result.formatted_summary.contains("Key timeline:"));
573	        assert!(should_compact(
574	            &session,
575	            CompactionConfig {
576	                preserve_recent_messages: 2,
577	                max_estimated_tokens: 1,
578	            }
579	        ));
580	        assert!(
581	            estimate_session_tokens(&result.compacted_session) < estimate_session_tokens(&session)
582	        );
583	    }
