585	    #[test]
586	    fn keeps_previous_compacted_context_when_compacting_again() {
587	        let mut initial_session = Session::new();
588	        initial_session.messages = vec![
589	            ConversationMessage::user_text("Investigate rust/crates/runtime/src/compact.rs"),
590	            ConversationMessage::assistant(vec![ContentBlock::Text {
591	                text: "I will inspect the compact flow.".to_string(),
592	            }]),
593	            ConversationMessage::user_text("Also update rust/crates/runtime/src/conversation.rs"),
594	            ConversationMessage::assistant(vec![ContentBlock::Text {
595	                text: "Next: preserve prior summary context during auto compact.".to_string(),
596	            }]),
597	        ];
598	        let config = CompactionConfig {
599	            preserve_recent_messages: 2,
600	            max_estimated_tokens: 1,
601	        };
602	
603	        let first = compact_session(&initial_session, config);
604	        let mut follow_up_messages = first.compacted_session.messages.clone();
605	        follow_up_messages.extend([
606	            ConversationMessage::user_text("Please add regression tests for compaction."),
607	            ConversationMessage::assistant(vec![ContentBlock::Text {
608	                text: "Working on regression coverage now.".to_string(),
609	            }]),
610	        ]);
611	
612	        let mut second_session = Session::new();
613	        second_session.messages = follow_up_messages;
614	        let second = compact_session(&second_session, config);
615	
616	        assert!(second
617	            .formatted_summary
618	            .contains("Previously compacted context:"));
619	        assert!(second
620	            .formatted_summary
621	            .contains("Scope: 2 earlier messages compacted"));
622	        assert!(second
623	            .formatted_summary
624	            .contains("Newly compacted context:"));
625	        assert!(second
626	            .formatted_summary
627	            .contains("Also update rust/crates/runtime/src/conversation.rs"));
628	        assert!(matches!(
629	            &second.compacted_session.messages[0].blocks[0],
630	            ContentBlock::Text { text }
631	                if text.contains("Previously compacted context:")
632	                    && text.contains("Newly compacted context:")
633	        ));
634	        assert!(matches!(
635	            &second.compacted_session.messages[1].blocks[0],
636	            ContentBlock::Text { text } if text.contains("Please add regression tests for compaction.")
637	        ));
638	    }
