295	    #[allow(clippy::too_many_lines)]
296	    pub fn run_turn(
297	        &mut self,
298	        user_input: impl Into<String>,
299	        mut prompter: Option<&mut dyn PermissionPrompter>,
300	    ) -> Result<TurnSummary, RuntimeError> {
301	        let user_input = user_input.into();
302	        self.record_turn_started(&user_input);
303	        self.session
304	            .push_user_text(user_input)
305	            .map_err(|error| RuntimeError::new(error.to_string()))?;
306	
307	        let mut assistant_messages = Vec::new();
308	        let mut tool_results = Vec::new();
309	        let mut prompt_cache_events = Vec::new();
310	        let mut iterations = 0;
311	
312	        loop {
313	            iterations += 1;
314	            if iterations > self.max_iterations {
315	                let error = RuntimeError::new(
316	                    "conversation loop exceeded the maximum number of iterations",
317	                );
318	                self.record_turn_failed(iterations, &error);
319	                return Err(error);
320	            }
321	
322	            if std::env::var("CLAW_LOG_API").is_ok() {
323	                eprintln!(
324	                    "\n########## ITERATION {iterations} (messages so far: {}) ##########",
325	                    self.session.messages.len()
326	                );
327	            }
328	            let request = ApiRequest {
329	                system_prompt: self.system_prompt.clone(),
330	                messages: self.session.messages.clone(),
331	            };
332	            let events = match self.api_client.stream(request) {
333	                Ok(events) => events,
334	                Err(error) => {
335	                    self.record_turn_failed(iterations, &error);
336	                    return Err(error);
337	                }
338	            };
339	            let (assistant_message, usage, turn_prompt_cache_events) =
340	                match build_assistant_message(events) {
341	                    Ok(result) => result,
342	                    Err(error) => {
343	                        self.record_turn_failed(iterations, &error);
344	                        return Err(error);
345	                    }
346	                };
347	            if let Some(usage) = usage {
348	                self.usage_tracker.record(usage);
349	            }
350	            prompt_cache_events.extend(turn_prompt_cache_events);
351	            let pending_tool_uses = assistant_message
352	                .blocks
353	                .iter()
354	                .filter_map(|block| match block {
355	                    ContentBlock::ToolUse { id, name, input } => {
356	                        Some((id.clone(), name.clone(), input.clone()))
357	                    }
358	                    _ => None,
359	                })
360	                .collect::<Vec<_>>();
361	            self.record_assistant_iteration(
362	                iterations,
363	                &assistant_message,
364	                pending_tool_uses.len(),
365	            );
366	
367	            self.session
368	                .push_message(assistant_message.clone())
369	                .map_err(|error| RuntimeError::new(error.to_string()))?;
370	            assistant_messages.push(assistant_message);
371	
372	            if pending_tool_uses.is_empty() {
373	                break;
374	            }
375	
376	            for (tool_use_id, tool_name, input) in pending_tool_uses {
377	                let pre_hook_result = self.run_pre_tool_use_hook(&tool_name, &input);
378	                let effective_input = pre_hook_result
379	                    .updated_input()
380	                    .map_or_else(|| input.clone(), ToOwned::to_owned);
381	                let permission_context = PermissionContext::new(
382	                    pre_hook_result.permission_override(),
383	                    pre_hook_result.permission_reason().map(ToOwned::to_owned),
384	                );
385	
386	                let permission_outcome = if pre_hook_result.is_cancelled() {
387	                    PermissionOutcome::Deny {
388	                        reason: format_hook_message(
389	                            &pre_hook_result,
390	                            &format!("PreToolUse hook cancelled tool `{tool_name}`"),
391	                        ),
392	                    }
393	                } else if pre_hook_result.is_failed() {
394	                    PermissionOutcome::Deny {
395	                        reason: format_hook_message(
396	                            &pre_hook_result,
397	                            &format!("PreToolUse hook failed for tool `{tool_name}`"),
398	                        ),
399	                    }
400	                } else if pre_hook_result.is_denied() {
401	                    PermissionOutcome::Deny {
402	                        reason: format_hook_message(
403	                            &pre_hook_result,
404	                            &format!("PreToolUse hook denied tool `{tool_name}`"),
405	                        ),
406	                    }
407	                } else if let Some(prompt) = prompter.as_mut() {
408	                    self.permission_policy.authorize_with_context(
409	                        &tool_name,
410	                        &effective_input,
411	                        &permission_context,
412	                        Some(*prompt),
413	                    )
414	                } else {
415	                    self.permission_policy.authorize_with_context(
416	                        &tool_name,
417	                        &effective_input,
418	                        &permission_context,
419	                        None,
420	                    )
421	                };
422	
423	                let result_message = match permission_outcome {
424	                    PermissionOutcome::Allow => {
425	                        self.record_tool_started(iterations, &tool_name);
426	                        let (mut output, mut is_error) =
427	                            match self.tool_executor.execute(&tool_name, &effective_input) {
428	                                Ok(output) => (output, false),
429	                                Err(error) => (error.to_string(), true),
430	                            };
431	                        output = merge_hook_feedback(pre_hook_result.messages(), output, false);
432	
433	                        let post_hook_result = if is_error {
434	                            self.run_post_tool_use_failure_hook(
435	                                &tool_name,
436	                                &effective_input,
437	                                &output,
438	                            )
439	                        } else {
440	                            self.run_post_tool_use_hook(
441	                                &tool_name,
442	                                &effective_input,
443	                                &output,
444	                                false,
445	                            )
446	                        };
447	                        if post_hook_result.is_denied()
448	                            || post_hook_result.is_failed()
449	                            || post_hook_result.is_cancelled()
450	                        {
451	                            is_error = true;
452	                        }
453	                        output = merge_hook_feedback(
454	                            post_hook_result.messages(),
455	                            output,
456	                            post_hook_result.is_denied()
457	                                || post_hook_result.is_failed()
458	                                || post_hook_result.is_cancelled(),
459	                        );
460	
461	                        ConversationMessage::tool_result(tool_use_id, tool_name, output, is_error)
462	                    }
463	                    PermissionOutcome::Deny { reason } => ConversationMessage::tool_result(
464	                        tool_use_id,
465	                        tool_name,
466	                        merge_hook_feedback(pre_hook_result.messages(), reason, true),
467	                        true,
468	                    ),
469	                };
470	                self.session
471	                    .push_message(result_message.clone())
472	                    .map_err(|error| RuntimeError::new(error.to_string()))?;
473	                self.record_tool_finished(iterations, &result_message);
474	                tool_results.push(result_message);
475	            }
476	        }
477	
478	        let auto_compaction = self.maybe_auto_compact();
479	
480	        let summary = TurnSummary {
481	            assistant_messages,
482	            tool_results,
483	            prompt_cache_events,
484	            iterations,
485	            usage: self.usage_tracker.cumulative_usage(),
486	            auto_compaction,
487	        };
488	        self.record_turn_completed(&summary);
489	
490	        Ok(summary)
491	    }
