317	    fn from_jsonl(contents: &str) -> Result<Self, SessionError> {
318	        let mut version = SESSION_VERSION;
319	        let mut session_id = None;
320	        let mut created_at_ms = None;
321	        let mut updated_at_ms = None;
322	        let mut messages = Vec::new();
323	        let mut compaction = None;
324	        let mut fork = None;
325	
326	        for (line_number, raw_line) in contents.lines().enumerate() {
327	            let line = raw_line.trim();
328	            if line.is_empty() {
329	                continue;
330	            }
331	            let value = JsonValue::parse(line).map_err(|error| {
332	                SessionError::Format(format!(
333	                    "invalid JSONL record at line {}: {}",
334	                    line_number + 1,
335	                    error
336	                ))
337	            })?;
338	            let object = value.as_object().ok_or_else(|| {
339	                SessionError::Format(format!(
340	                    "JSONL record at line {} must be an object",
341	                    line_number + 1
342	                ))
343	            })?;
344	            match object
345	                .get("type")
346	                .and_then(JsonValue::as_str)
347	                .ok_or_else(|| {
348	                    SessionError::Format(format!(
349	                        "JSONL record at line {} missing type",
350	                        line_number + 1
351	                    ))
352	                })? {
353	                "session_meta" => {
354	                    version = required_u32(object, "version")?;
355	                    session_id = Some(required_string(object, "session_id")?);
356	                    created_at_ms = Some(required_u64(object, "created_at_ms")?);
357	                    updated_at_ms = Some(required_u64(object, "updated_at_ms")?);
358	                    fork = object.get("fork").map(SessionFork::from_json).transpose()?;
359	                }
360	                "message" => {
361	                    let message_value = object.get("message").ok_or_else(|| {
362	                        SessionError::Format(format!(
363	                            "JSONL record at line {} missing message",
364	                            line_number + 1
365	                        ))
366	                    })?;
367	                    messages.push(ConversationMessage::from_json(message_value)?);
368	                }
369	                "compaction" => {
370	                    compaction = Some(SessionCompaction::from_json(&JsonValue::Object(
371	                        object.clone(),
372	                    ))?);
373	                }
374	                other => {
375	                    return Err(SessionError::Format(format!(
376	                        "unsupported JSONL record type at line {}: {other}",
377	                        line_number + 1
378	                    )))
379	                }
380	            }
381	        }
382	
383	        let now = current_time_millis();
384	        Ok(Self {
385	            version,
386	            session_id: session_id.unwrap_or_else(generate_session_id),
387	            created_at_ms: created_at_ms.unwrap_or(now),
388	            updated_at_ms: updated_at_ms.unwrap_or(created_at_ms.unwrap_or(now)),
389	            messages,
390	            compaction,
391	            fork,
392	            persistence: None,
393	        })
394	    }
