193	        let ask_rule = Self::find_matching_rule(&self.ask_rules, tool_name, input);
194	        let allow_rule = Self::find_matching_rule(&self.allow_rules, tool_name, input);
195	
196	        match context.override_decision() {
197	            Some(PermissionOverride::Deny) => {
198	                return PermissionOutcome::Deny {
199	                    reason: context.override_reason().map_or_else(
