274	            ));
275	            return Self::prompt_or_deny(
276	                tool_name,
277	                input,
278	                current_mode,
279	                required_mode,
280	                reason,
281	                prompter,
282	            );
283	        }
284	
285	        PermissionOutcome::Deny {
286	            reason: format!(
