342	#[derive(Debug, Clone, PartialEq, Eq)]
343	enum PermissionRuleMatcher {
344	    Any,
345	    Exact(String),
346	    Prefix(String),
347	}
348	
349	impl PermissionRule {
350	    fn parse(raw: &str) -> Self {
351	        let trimmed = raw.trim();
352	        let open = find_first_unescaped(trimmed, '(');
353	        let close = find_last_unescaped(trimmed, ')');
354	
355	        if let (Some(open), Some(close)) = (open, close) {
356	            if close == trimmed.len() - 1 && open < close {
357	                let tool_name = trimmed[..open].trim();
358	                let content = &trimmed[open + 1..close];
359	                if !tool_name.is_empty() {
360	                    let matcher = parse_rule_matcher(content);
361	                    return Self {
362	                        raw: trimmed.to_string(),
363	                        tool_name: tool_name.to_string(),
364	                        matcher,
365	                    };
366	                }
367	            }
368	        }
369	
370	        Self {
371	            raw: trimmed.to_string(),
372	            tool_name: trimmed.to_string(),
373	            matcher: PermissionRuleMatcher::Any,
374	        }
375	    }
376	
377	    fn matches(&self, tool_name: &str, input: &str) -> bool {
378	        if self.tool_name != tool_name {
379	            return false;
380	        }
381	
382	        match &self.matcher {
383	            PermissionRuleMatcher::Any => true,
384	            PermissionRuleMatcher::Exact(expected) => {
385	                extract_permission_subject(input).is_some_and(|candidate| candidate == *expected)
386	            }
387	            PermissionRuleMatcher::Prefix(prefix) => extract_permission_subject(input)
388	                .is_some_and(|candidate| candidate.starts_with(prefix)),
389	        }
390	    }
391	}
