674	fn build_assistant_message(
675	    events: Vec<AssistantEvent>,
676	) -> Result<
677	    (
678	        ConversationMessage,
679	        Option<TokenUsage>,
680	        Vec<PromptCacheEvent>,
681	    ),
682	    RuntimeError,
683	> {
684	    let mut text = String::new();
685	    let mut blocks = Vec::new();
686	    let mut prompt_cache_events = Vec::new();
687	    let mut finished = false;
688	    let mut usage = None;
689	
690	    for event in events {
691	        match event {
692	            AssistantEvent::TextDelta(delta) => text.push_str(&delta),
693	            AssistantEvent::ToolUse { id, name, input } => {
694	                flush_text_block(&mut text, &mut blocks);
695	                blocks.push(ContentBlock::ToolUse { id, name, input });
696	            }
697	            AssistantEvent::Usage(value) => usage = Some(value),
698	            AssistantEvent::PromptCache(event) => prompt_cache_events.push(event),
699	            AssistantEvent::MessageStop => {
700	                finished = true;
701	            }
702	        }
703	    }
704	
705	    flush_text_block(&mut text, &mut blocks);
706	
707	    if !finished {
708	        return Err(RuntimeError::new(
709	            "assistant stream ended without a message stop event",
710	        ));
711	    }
712	    if blocks.is_empty() {
713	        return Err(RuntimeError::new("assistant stream produced no content"));
714	    }
715	
716	    Ok((
717	        ConversationMessage::assistant_with_usage(blocks, usage),
718	        usage,
719	        prompt_cache_events,
720	    ))
721	}
