739	fn merge_hook_feedback(messages: &[String], output: String, is_error: bool) -> String {
740	    if messages.is_empty() {
741	        return output;
742	    }
743	
744	    let mut sections = Vec::new();
745	    if !output.trim().is_empty() {
746	        sections.push(output);
747	    }
748	    let label = if is_error {
749	        "Hook feedback (error)"
750	    } else {
751	        "Hook feedback"
752	    };
753	    sections.push(format!("{label}:\n{}", messages.join("\n")));

