535	fn parse_hook_output(stdout: &str) -> ParsedHookOutput {
536	    if stdout.is_empty() {
537	        return ParsedHookOutput::default();
538	    }
539	
540	    let Ok(Value::Object(root)) = serde_json::from_str::<Value>(stdout) else {
541	        return ParsedHookOutput {
542	            messages: vec![stdout.to_string()],
543	            ..ParsedHookOutput::default()
544	        };
545	    };
546	
547	    let mut parsed = ParsedHookOutput::default();
548	
549	    if let Some(message) = root.get("systemMessage").and_then(Value::as_str) {
550	        parsed.messages.push(message.to_string());
551	    }
552	    if let Some(message) = root.get("reason").and_then(Value::as_str) {
553	        parsed.messages.push(message.to_string());
554	    }
555	    if root.get("continue").and_then(Value::as_bool) == Some(false)
556	        || root.get("decision").and_then(Value::as_str) == Some("block")
557	    {
558	        parsed.deny = true;
559	    }
560	
561	    if let Some(Value::Object(specific)) = root.get("hookSpecificOutput") {
562	        if let Some(Value::String(additional_context)) = specific.get("additionalContext") {
563	            parsed.messages.push(additional_context.clone());
564	        }
565	        if let Some(decision) = specific.get("permissionDecision").and_then(Value::as_str) {
566	            parsed.permission_override = match decision {
567	                "allow" => Some(PermissionOverride::Allow),
568	                "deny" => Some(PermissionOverride::Deny),
569	                "ask" => Some(PermissionOverride::Ask),
570	                _ => None,
571	            };
572	        }
573	        if let Some(reason) = specific
574	            .get("permissionDecisionReason")
575	            .and_then(Value::as_str)
576	        {
577	            parsed.permission_reason = Some(reason.to_string());
578	        }
579	        if let Some(updated_input) = specific.get("updatedInput") {
580	            parsed.updated_input = serde_json::to_string(updated_input).ok();
581	        }
582	    }
583	
584	    if parsed.messages.is_empty() {
585	        parsed.messages.push(stdout.to_string());
586	    }
587	
588	    parsed
589	}
