def parse_sse_events(raw_sse):
    """Parse SSE text into a list of parsed JSON events."""
    events = []
    for line in raw_sse.split("\n"):
        line = line.strip()
        if line.startswith("data: "):
            payload = line[6:]
            if payload == "[DONE]":
                continue
            try:
                events.append(json.loads(payload))
            except json.JSONDecodeError:
                events.append({"_raw": payload})
    return events


def summarize_sse_response(events):
    """Build a human-readable summary of SSE events."""
    lines = []
    text_parts = []
    thinking_parts = []
    tool_uses = []
    usage = None
    stop_reason = None

    for event in events:
        etype = event.get("type", "?")
        if etype == "message_start":
            msg = event.get("message", {})
            lines.append(f"Model: {msg.get('model', '?')}")
            lines.append(f"Message ID: {msg.get('id', '?')}")
            usage = msg.get("usage", {})
        elif etype == "content_block_start":
            block = event.get("content_block", {})
            btype = block.get("type", "?")
            if btype == "tool_use":
                tool_uses.append({
                    "id": block.get("id", "?"),
                    "name": block.get("name", "?"),
                    "input": "",
                })
            elif btype == "thinking":
                pass  # thinking deltas collected below
        elif etype == "content_block_delta":
            delta = event.get("delta", {})
            dtype = delta.get("type", "?")
            if dtype == "text_delta":
                text_parts.append(delta.get("text", ""))
            elif dtype == "input_json_delta":
                if tool_uses:
                    tool_uses[-1]["input"] += delta.get("partial_json", "")
            elif dtype == "thinking_delta":
                thinking_parts.append(delta.get("thinking", ""))
        elif etype == "message_delta":
            delta = event.get("delta", {})
            stop_reason = delta.get("stop_reason")
            msg_usage = event.get("usage", {})
            if msg_usage:
                usage = {**(usage or {}), **msg_usage}

    full_text = "".join(text_parts)
    full_thinking = "".join(thinking_parts)

    if full_thinking:
        lines.append(f"\nThinking ({len(full_thinking)} chars):")
        preview = full_thinking[:500]
        lines.append(f"  {preview}{'...' if len(full_thinking) > 500 else ''}")

    if full_text:
        lines.append(f"\nText output ({len(full_text)} chars):")
        preview = full_text[:1000]
        lines.append(f"  {preview}{'...' if len(full_text) > 1000 else ''}")

    if tool_uses:
        lines.append(f"\nTool calls ({len(tool_uses)}):")
        for t in tool_uses:
            inp_preview = t["input"][:200] + "..." if len(t["input"]) > 200 else t["input"]
            lines.append(f"  - {t['name']} (id={t['id']})")
            lines.append(f"    input: {inp_preview}")

    lines.append(f"\nStop reason: {stop_reason}")

    if usage:
        lines.append(f"\nUsage:")
        for k, v in usage.items():
            if isinstance(v, (int, float)) and v > 0:
                lines.append(f"  {k}: {v}")

    return "\n".join(lines), {
        "text": full_text,
        "thinking": full_thinking,
        "tool_uses": tool_uses,
        "stop_reason": stop_reason,
        "usage": usage,
    }


def save_response(iteration, body, is_sse=False, is_error=False, status=200):
    """Save the API response for an iteration."""
    try:
        os.makedirs(CAPTURE_DIR, exist_ok=True)

        # Save raw response
        raw_path = os.path.join(CAPTURE_DIR, f"iteration_{iteration:03d}_response_raw.txt")
        with open(raw_path, "w") as f:
            f.write(body)

        # Save parsed summary
        summary_path = os.path.join(CAPTURE_DIR, f"iteration_{iteration:03d}_response_summary.txt")
        lines = [
            f"{'=' * 70}",
            f"ITERATION {iteration} вАФ RESPONSE",
            f"{'=' * 70}",
            "",
        ]

        if is_error:
            lines.append(f"ERROR (status {status}):")
            lines.append(body[:2000])
        elif is_sse:
            events = parse_sse_events(body)
            lines.append(f"SSE events: {len(events)}")
            summary_text, parsed = summarize_sse_response(events)
            lines.append(summary_text)

            # Also save structured parsed response
            parsed_path = os.path.join(CAPTURE_DIR, f"iteration_{iteration:03d}_response_parsed.json")
            with open(parsed_path, "w") as f:
                json.dump(parsed, f, indent=2, ensure_ascii=False)
        else:
            # Non-streaming JSON response
            try:
                data = json.loads(body)
                parsed_path = os.path.join(CAPTURE_DIR, f"iteration_{iteration:03d}_response_parsed.json")
                with open(parsed_path, "w") as f:
                    json.dump(data, f, indent=2, ensure_ascii=False)

                # Summarize
                content = data.get("content", [])
                for block in content:
                    btype = block.get("type", "?")
                    if btype == "text":
                        text = block.get("text", "")
                        lines.append(f"Text ({len(text)} chars): {text[:500]}")
                    elif btype == "tool_use":
                        lines.append(f"Tool use: {block.get('name', '?')} (id={block.get('id','?')})")
                usage = data.get("usage", {})
                if usage:
                    lines.append(f"\nUsage:")
                    for k, v in usage.items():
                        if isinstance(v, (int, float)) and v > 0:
                            lines.append(f"  {k}: {v}")
            except json.JSONDecodeError:
                lines.append(f"Non-JSON response ({len(body)} chars):")
                lines.append(body[:2000])

        with open(summary_path, "w") as f:
            f.write("\n".join(lines))

        print(f"[proxy] Iteration {iteration} response saved ({len(body)} chars)", file=sys.stderr)

    except Exception as e:
        print(f"[proxy] Failed to save response for iteration {iteration}: {e}", file=sys.stderr)


