function renderFlowMap() {
  const container = document.getElementById('flowmap');
  const parent = DATA.agents.find(a => a.id === 'parent');
  if (!parent) { container.innerHTML = '<p style="color:var(--text-dim)">No parent agent found.</p>'; return; }
  const subagents = DATA.agents.filter(a => a.type === 'subagent');

  // Layout config
  const nodeW = 160, nodeH = 36, gapY = 8, gapX = 40;
  const laneWidth = nodeW + gapX;
  const headerH = 50;
  const lanes = ['parent', ...subagents.map(a => a.id)];
  const laneX = {};
  lanes.forEach((id, i) => { laneX[id] = 40 + i * laneWidth; });

  // Build node list: assign each iteration to a lane and a row
  // Rows are chronological вАФ we interleave all iterations by their number
  const allNodes = [];

  // Parent iterations
  for (const it of parent.iterations) {
    allNodes.push({ num: it.number, agent_id: 'parent', iteration: it, type: 'agent' });
  }
  // Subagent iterations
  for (const sa of subagents) {
    for (const it of sa.iterations) {
      allNodes.push({ num: it.number, agent_id: sa.id, iteration: it, type: 'subagent' });
    }
  }
  // Internal
  for (const ic of DATA.internal_calls) {
    allNodes.push({ num: ic.number, agent_id: 'internal', iteration: ic, type: 'internal' });
  }
  allNodes.sort((a, b) => a.num - b.num);

  // Assign Y positions вАФ each node gets a row, but parallel subagent iterations
  // on the same "row" share the Y if they're close in number
  // Simple approach: assign Y sequentially per lane, tracking max Y globally
  const laneY = {};
  lanes.forEach(id => { laneY[id] = headerH; });
  let globalY = headerH;

  const nodePositions = []; // {num, x, y, w, h, agent_id, type, iteration}

  // Group by chronological order, advance Y for each "wave"
  // A wave is a set of iterations that happen roughly at the same time
  let lastParentY = headerH;

  for (const node of allNodes) {
    if (node.type === 'internal') continue; // skip internals in flow map

    const lane = node.agent_id;
    if (!laneX[lane] && lane !== 'parent') continue;

    const x = laneX[lane] || laneX['parent'];
    const y = Math.max(laneY[lane] || headerH, globalY);

    nodePositions.push({
      num: node.num,
      x, y, w: nodeW, h: nodeH,
      agent_id: lane,
      type: node.type,
      iteration: node.iteration,
    });

    laneY[lane] = y + nodeH + gapY;
    // Advance global Y only when parent advances (to keep subagents parallel)
    if (lane === 'parent') {
      globalY = y + nodeH + gapY;
      lastParentY = y;
    } else {
      // Don't advance global Y for subagents вАФ they stack in their own lane
    }
  }

  const totalH = Math.max(...Object.values(laneY), globalY) + 40;
  const totalW = 40 + lanes.length * laneWidth + 40;

  // Build SVG
  let svg = `<svg width="${totalW}" height="${totalH}" xmlns="http://www.w3.org/2000/svg">`;

  // Lane headers
  for (const lane of lanes) {
    const x = laneX[lane];
    const color = getAgentColor(lane);
    const label = lane === 'parent' ? 'Main Agent' : (subagents.find(a=>a.id===lane)?.task?.substring(0,20)+'...' || lane);
    svg += `<text x="${x + nodeW/2}" y="20" text-anchor="middle" class="flow-legend" style="fill:${color};font-weight:600">${esc(label)}</text>`;
    // Lane line
    svg += `<line x1="${x + nodeW/2}" y1="30" x2="${x + nodeW/2}" y2="${totalH-20}" stroke="${color}" stroke-width="1" opacity="0.15"/>`;
  }

  // Find fork and merge points
  // Fork: parent iteration that spawns agents (has spawned_agents)
  // Merge: parent iteration after subagents finish (the one with tool_results for agents)
  const forkNode = nodePositions.find(n => n.agent_id === 'parent' && n.iteration.spawned_agents?.length > 0);
  // Merge: first parent node after the fork that doesn't spawn
  const forkIdx = forkNode ? nodePositions.indexOf(forkNode) : -1;
  const mergeNode = forkIdx >= 0 ? nodePositions.find((n, i) => i > forkIdx && n.agent_id === 'parent') : null;

  // Draw fork lines (parent вЖТ first iteration of each subagent)
  if (forkNode) {
    for (const sa of subagents) {
      const firstSub = nodePositions.find(n => n.agent_id === sa.id);
      if (!firstSub) continue;
      const color = getAgentColor(sa.id);
      const x1 = forkNode.x + nodeW/2;
      const y1 = forkNode.y + nodeH;
      const x2 = firstSub.x + nodeW/2;
      const y2 = firstSub.y;
      const midY = y1 + (y2 - y1) * 0.5;
      svg += `<path d="M${x1},${y1} C${x1},${midY} ${x2},${midY} ${x2},${y2}" class="flow-line" stroke="${color}"/>`;
    }
  }

  // Draw merge lines (last iteration of each subagent вЖТ merge parent node)
  if (mergeNode) {
    for (const sa of subagents) {
      const lastSub = [...nodePositions].reverse().find(n => n.agent_id === sa.id);
      if (!lastSub) continue;
      const color = getAgentColor(sa.id);
      const x1 = lastSub.x + nodeW/2;
      const y1 = lastSub.y + nodeH;
      const x2 = mergeNode.x + nodeW/2;
      const y2 = mergeNode.y;
      const midY = y1 + (y2 - y1) * 0.5;
      svg += `<path d="M${x1},${y1} C${x1},${midY} ${x2},${midY} ${x2},${y2}" class="flow-line flow-merge-line" stroke="${color}"/>`;
    }
  }

  // Draw connection lines within each lane (sequential iterations)
  for (const lane of lanes) {
    const laneNodes = nodePositions.filter(n => n.agent_id === lane);
    const color = getAgentColor(lane);
    for (let i = 1; i < laneNodes.length; i++) {
      const prev = laneNodes[i-1];
      const curr = laneNodes[i];
      // Skip if fork/merge lines already handle this
      if (lane === 'parent' && forkNode && mergeNode && prev.num === forkNode.num && curr.num === mergeNode.num) continue;
      svg += `<line x1="${prev.x+nodeW/2}" y1="${prev.y+nodeH}" x2="${curr.x+nodeW/2}" y2="${curr.y}" class="flow-line" stroke="${color}"/>`;
    }
  }

  // Draw nodes
  for (const node of nodePositions) {
    const color = getAgentColor(node.agent_id);
    const hasError = node.iteration.errors?.length > 0;
    const strokeColor = hasError ? '#f85149' : color;
    const tools = node.iteration.response?.tool_uses?.map(t=>t.name).join(', ') || '';
    const text = node.iteration.response?.text ? 'text' : '';
    const label = tools || text || (node.iteration.response?.stop_reason === 'end_turn' ? 'final' : '');
    const dur = node.iteration.duration_ms ? fmtDuration(node.iteration.duration_ms) : '';
    const selectedClass = selectedIteration === node.num ? ' selected' : '';

    svg += `<g class="flow-node${selectedClass}" data-num="${node.num}" onclick="openDetail(${node.num})">`;
    svg += `<rect x="${node.x}" y="${node.y}" width="${nodeW}" height="${nodeH}" fill="#161b22" stroke="${strokeColor}"/>`;
    svg += `<text x="${node.x+8}" y="${node.y+15}" class="node-label" style="fill:${color}">#${String(node.num).padStart(3,'0')}</text>`;
    svg += `<text x="${node.x+50}" y="${node.y+15}" style="font-size:10px;fill:#8b949e">${esc(label).substring(0,14)}</text>`;
    if (dur) svg += `<text x="${node.x+nodeW-8}" y="${node.y+28}" text-anchor="end" style="font-size:9px;fill:#484f58">${dur}</text>`;
    if (hasError) svg += `<circle cx="${node.x+nodeW-12}" cy="${node.y+12}" r="4" fill="#f85149"/>`;
    svg += `</g>`;
  }

  svg += `</svg>`;

  // Legend
  let legend = '<div style="padding:10px 0;display:flex;gap:16px;font-size:12px;color:var(--text-dim)">';
  legend += `<span><span style="display:inline-block;width:12px;height:12px;border-radius:2px;background:${getAgentColor('parent')};vertical-align:middle;margin-right:4px"></span>Main Agent</span>`;
  for (const sa of subagents) {
    const color = getAgentColor(sa.id);
    const label = sa.task?.substring(0, 25) || sa.id;
    legend += `<span><span style="display:inline-block;width:12px;height:12px;border-radius:2px;background:${color};vertical-align:middle;margin-right:4px"></span>${esc(label)}...</span>`;
  }
  legend += `<span style="margin-left:auto"><span style="border-bottom:2px dashed var(--text-dim);display:inline-block;width:20px;vertical-align:middle;margin-right:4px"></span>merge</span>`;
  legend += '</div>';

  container.innerHTML = legend + svg;
}

