function renderFlowMap() {
  const container = document.getElementById('flowmap');
  const parent = DATA.agents.find(a => a.id === 'parent');
  if (!parent) { container.innerHTML = '<p style="color:var(--text-dim)">No parent agent found.</p>'; return; }
  const subagents = DATA.agents.filter(a => a.type === 'subagent');

  // Layout
  const nodeW = 180, nodeH = 42, gapY = 6, laneGap = 50;
  const laneWidth = nodeW + laneGap;
  const headerH = 70;
  const marginL = 50, marginR = 50;
  const forkZoneH = 60, mergeZoneH = 60;

  // Lanes: parent on the left, subagents to the right
  const lanes = ['parent', ...subagents.map(a => a.id)];
  const laneX = {};
  lanes.forEach((id, i) => { laneX[id] = marginL + i * laneWidth; });

  // Separate parent iterations into: before-fork, fork, after-merge
  const forkIter = parent.iterations.find(it => it.spawned_agents?.length > 0);
  const forkIdx = forkIter ? parent.iterations.indexOf(forkIter) : -1;
  const preFork = forkIdx >= 0 ? parent.iterations.slice(0, forkIdx) : parent.iterations;
  const postFork = forkIdx >= 0 ? parent.iterations.slice(forkIdx + 1) : [];

  // Layout Y positions
  let y = headerH;
  const nodes = []; // {num, x, y, w, h, agent_id, iteration, phase}

  // Phase 1: Pre-fork parent iterations
  for (const it of preFork) {
    nodes.push({ num: it.number, x: laneX['parent'], y, w: nodeW, h: nodeH, agent_id: 'parent', iteration: it, phase: 'pre' });
    y += nodeH + gapY;
  }

  // Phase 2: Fork node
  let forkY = y;
  if (forkIter) {
    nodes.push({ num: forkIter.number, x: laneX['parent'], y, w: nodeW, h: nodeH, agent_id: 'parent', iteration: forkIter, phase: 'fork' });
    y += nodeH + forkZoneH; // extra space for fork lines
  }

  // Phase 3: Parallel subagent iterations вАФ each lane stacks independently
  const subStartY = y;
  const laneEndY = {};
  for (const sa of subagents) {
    let sy = subStartY;
    for (const it of sa.iterations) {
      nodes.push({ num: it.number, x: laneX[sa.id], y: sy, w: nodeW, h: nodeH, agent_id: sa.id, iteration: it, phase: 'parallel' });
      sy += nodeH + gapY;
    }
    laneEndY[sa.id] = sy;
  }

  // Merge Y = after the longest subagent lane
  const maxSubY = Math.max(...Object.values(laneEndY), subStartY);
  y = maxSubY + mergeZoneH;

  // Phase 4: Post-fork parent iterations (merge + continue)
  const mergeY = y;
  for (const it of postFork) {
    nodes.push({ num: it.number, x: laneX['parent'], y, w: nodeW, h: nodeH, agent_id: 'parent', iteration: it, phase: 'post' });
    y += nodeH + gapY;
  }

  const totalW = marginL + lanes.length * laneWidth + marginR;
  const totalH = y + 40;

  // Build SVG
  let svg = `<svg width="${totalW}" height="${totalH}" xmlns="http://www.w3.org/2000/svg">`;

  // Arrow marker defs
  svg += `<defs>`;
  for (const lane of lanes) {
    const color = getAgentColor(lane);
    svg += `<marker id="arrow-${lane}" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto"><path d="M0,0 L8,3 L0,6 Z" fill="${color}"/></marker>`;
  }
  svg += `<marker id="arrow-merge" markerWidth="8" markerHeight="6" refX="8" refY="3" orient="auto"><path d="M0,0 L8,3 L0,6 Z" fill="#8b949e"/></marker>`;
  svg += `</defs>`;

  // Lane headers with background
  for (const lane of lanes) {
    const x = laneX[lane];
    const color = getAgentColor(lane);
    const sa = subagents.find(a => a.id === lane);
    const label = lane === 'parent' ? 'Main Agent' : (sa?.parent_description || sa?.task?.substring(0, 22) || lane);
    const iterCount = lane === 'parent' ? parent.iterations.length : (sa?.iterations.length || 0);

    // Header box
    svg += `<rect x="${x-4}" y="8" width="${nodeW+8}" height="46" rx="8" fill="${color}" opacity="0.08"/>`;
    svg += `<text x="${x + nodeW/2}" y="28" text-anchor="middle" style="fill:${color};font-weight:700;font-size:13px">${esc(label).substring(0,22)}</text>`;
    svg += `<text x="${x + nodeW/2}" y="44" text-anchor="middle" style="fill:${color};font-size:10px;opacity:0.7">${iterCount} iterations</text>`;

    // Lane guide line (very subtle)
    const laneNodes = nodes.filter(n => n.agent_id === lane);
    if (laneNodes.length > 0) {
      const firstY = laneNodes[0].y;
      const lastY = laneNodes[laneNodes.length-1].y + nodeH;
      svg += `<line x1="${x+nodeW/2}" y1="${firstY-4}" x2="${x+nodeW/2}" y2="${lastY+4}" stroke="${color}" stroke-width="1" opacity="0.08"/>`;
    }
  }

  // Sequential lines within each lane (with arrows)
  for (const lane of lanes) {
    const laneNodes = nodes.filter(n => n.agent_id === lane);
    const color = getAgentColor(lane);
    for (let i = 1; i < laneNodes.length; i++) {
      const prev = laneNodes[i-1];
      const curr = laneNodes[i];
      // Skip the gap between fork and post-merge for parent
      if (lane === 'parent' && prev.phase === 'fork' && curr.phase === 'post') continue;
      const x = prev.x + nodeW/2;
      svg += `<line x1="${x}" y1="${prev.y+nodeH}" x2="${x}" y2="${curr.y}" stroke="${color}" stroke-width="2" opacity="0.5" marker-end="url(#arrow-${lane})"/>`;
    }
  }

  // Fork lines: parent fork node вЖТ first subagent iteration (with label)
  const forkNode = nodes.find(n => n.phase === 'fork');
  if (forkNode) {
    for (const sa of subagents) {
      const firstSub = nodes.find(n => n.agent_id === sa.id);
      if (!firstSub) continue;
      const color = getAgentColor(sa.id);
      const x1 = forkNode.x + nodeW;  // exit from right side of fork node
      const y1 = forkNode.y + nodeH/2;
      const x2 = firstSub.x;           // enter left side of first subagent node
      const y2 = firstSub.y + nodeH/2;
      // Curved path: right from parent, curve down to subagent
      const cx1 = x1 + 30;
      const cy1 = y1;
      const cx2 = x2 - 30;
      const cy2 = y2;
      svg += `<path d="M${x1},${y1} C${cx1},${cy1} ${cx2},${cy2} ${x2},${y2}" fill="none" stroke="${color}" stroke-width="2.5" opacity="0.7" marker-end="url(#arrow-${sa.id})"/>`;

      // "spawn" label on the line
      const midX = (x1 + x2) / 2;
      const midY = (y1 + y2) / 2 - 6;
      svg += `<text x="${midX}" y="${midY}" text-anchor="middle" style="font-size:9px;fill:${color};font-weight:600;opacity:0.8">spawn</text>`;
    }

    // Dashed line from parent fork down to merge (shows parent is waiting)
    const mergeNode = nodes.find(n => n.phase === 'post');
    if (mergeNode) {
      const px = forkNode.x + nodeW/2;
      svg += `<line x1="${px}" y1="${forkNode.y+nodeH}" x2="${px}" y2="${mergeNode.y}" stroke="${getAgentColor('parent')}" stroke-width="1.5" stroke-dasharray="6,4" opacity="0.25"/>`;
      svg += `<text x="${px+10}" y="${(forkNode.y+nodeH+mergeNode.y)/2}" style="font-size:9px;fill:var(--text-dim);opacity:0.6" transform="rotate(90,${px+10},${(forkNode.y+nodeH+mergeNode.y)/2})">waiting</text>`;
    }
  }

  // Merge lines: last subagent iteration вЖТ first post-fork parent node (with label)
  const mergeNode = nodes.find(n => n.phase === 'post');
  if (mergeNode) {
    for (const sa of subagents) {
      const lastSub = [...nodes].reverse().find(n => n.agent_id === sa.id);
      if (!lastSub) continue;
      const color = getAgentColor(sa.id);
      const x1 = lastSub.x + nodeW;    // exit from right of last subagent
      const y1 = lastSub.y + nodeH/2;
      const x2 = mergeNode.x;           // enter left of merge node
      const y2 = mergeNode.y + nodeH/2;
      const cx1 = x1 + 30;
      const cy1 = y1;
      const cx2 = x2 - 30;
      const cy2 = y2;
      svg += `<path d="M${x1},${y1} C${cx1},${cy1} ${cx2},${cy2} ${x2},${y2}" fill="none" stroke="${color}" stroke-width="2" stroke-dasharray="8,4" opacity="0.6" marker-end="url(#arrow-merge)"/>`;

      // "result" label
      const midX = (x1 + x2) / 2;
      const midY = (y1 + y2) / 2 - 6;
      svg += `<text x="${midX}" y="${midY}" text-anchor="middle" style="font-size:9px;fill:${color};opacity:0.7">result</text>`;
    }
  }

  // Draw nodes (on top of lines)
  for (const node of nodes) {
    const color = getAgentColor(node.agent_id);
    const hasError = node.iteration.errors?.length > 0;
    const isFork = node.phase === 'fork';
    const isMerge = node.phase === 'post' && postFork.indexOf(node.iteration) === 0;
    const strokeColor = hasError ? '#f85149' : color;
    const strokeW = (isFork || isMerge) ? 2.5 : 1.5;
    const fillColor = (isFork || isMerge) ? color + '15' : '#161b22';

    const tools = node.iteration.response?.tool_uses?.map(t => t.name) || [];
    const hasText = node.iteration.response?.text;
    const stopReason = node.iteration.response?.stop_reason;
    let label = tools.join(', ');
    if (!label && hasText) label = 'text response';
    if (!label && stopReason === 'end_turn') label = 'final answer';
    if (isFork) label = 'spawns ' + (forkIter.spawned_agents?.length || subagents.length) + ' agents';
    if (isMerge) label = 'receives results';
    const dur = node.iteration.duration_ms ? fmtDuration(node.iteration.duration_ms) : '';
    const msgCount = node.iteration.messages_count || 0;
    const selClass = selectedIteration === node.num ? ' selected' : '';

    svg += `<g class="flow-node${selClass}" onclick="openDetail(${node.num})">`;
    svg += `<rect x="${node.x}" y="${node.y}" width="${nodeW}" height="${nodeH}" fill="${fillColor}" stroke="${strokeColor}" stroke-width="${strokeW}"/>`;
    // Row 1: number + tool/label
    svg += `<text x="${node.x+10}" y="${node.y+16}" class="node-label" style="fill:${color}">#${String(node.num).padStart(3,'0')}</text>`;
    svg += `<text x="${node.x+52}" y="${node.y+16}" style="font-size:10px;fill:#c9d1d9">${esc(label).substring(0,16)}</text>`;
    // Row 2: duration + message count
    svg += `<text x="${node.x+10}" y="${node.y+32}" style="font-size:9px;fill:#484f58">${msgCount} msgs</text>`;
    if (dur) svg += `<text x="${node.x+nodeW-10}" y="${node.y+32}" text-anchor="end" style="font-size:9px;fill:#484f58">${dur}</text>`;
    // Error indicator
    if (hasError) {
      svg += `<rect x="${node.x}" y="${node.y}" width="3" height="${nodeH}" fill="#f85149" rx="1"/>`;
      svg += `<circle cx="${node.x+nodeW-14}" cy="${node.y+14}" r="5" fill="#f85149" opacity="0.8"/>`;
      svg += `<text x="${node.x+nodeW-14}" y="${node.y+17}" text-anchor="middle" style="font-size:8px;fill:white;font-weight:700">!</text>`;
    }
    svg += `</g>`;
  }

  svg += `</svg>`;

  // Legend
  let legend = '<div style="padding:12px 0;display:flex;flex-wrap:wrap;gap:16px;font-size:12px;color:var(--text-dim);align-items:center">';
  legend += `<span style="font-weight:600;color:var(--text)">Flow Map</span>`;
  legend += `<span><span style="display:inline-block;width:14px;height:14px;border-radius:3px;background:${getAgentColor('parent')};vertical-align:middle;margin-right:4px"></span>Main Agent</span>`;
  for (const sa of subagents) {
    const color = getAgentColor(sa.id);
    const label = sa.parent_description || sa.task?.substring(0, 20) || sa.id;
    legend += `<span><span style="display:inline-block;width:14px;height:14px;border-radius:3px;background:${color};vertical-align:middle;margin-right:4px"></span>${esc(label)}...</span>`;
  }
  legend += `<span style="margin-left:auto;display:flex;gap:12px">`;
  legend += `<span><svg width="24" height="12"><line x1="0" y1="6" x2="24" y2="6" stroke="var(--text-dim)" stroke-width="2"/></svg> flow</span>`;
  legend += `<span><svg width="24" height="12"><line x1="0" y1="6" x2="24" y2="6" stroke="var(--text-dim)" stroke-width="2" stroke-dasharray="6,3"/></svg> result/wait</span>`;
  legend += `<span><span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:#f85149;vertical-align:middle;margin-right:4px"></span>error</span>`;
  legend += `</span></div>`;

  container.innerHTML = legend + svg;
}

