462	
463	  // Separate parent iterations into: before-fork, fork, after-merge
464	  const forkIter = parent.iterations.find(it => it.spawned_agents?.length > 0);
465	  const forkIdx = forkIter ? parent.iterations.indexOf(forkIter) : -1;
466	  const preFork = forkIdx >= 0 ? parent.iterations.slice(0, forkIdx) : parent.iterations;
467	  const postFork = forkIdx >= 0 ? parent.iterations.slice(forkIdx + 1) : [];
