def load_json(path):
    try:
        with open(path) as f:
            return json.load(f)
    except (json.JSONDecodeError, FileNotFoundError, OSError):
        return None


def try_decompress_and_parse_sse(raw_path):
    """Try to decompress a gzip SSE response and parse it."""
    import gzip
    try:
        with open(raw_path, "rb") as f:
            raw = f.read()
        if not raw or raw[:2] != b'\x1f\x8b':
            return None  # not gzip
        decompressed = gzip.decompress(raw).decode("utf-8", errors="replace")
        return parse_sse_text(decompressed)
    except Exception:
        return None


def parse_sse_text(text):
    """Parse SSE text into structured response data."""
    events = []
    for line in text.split("\n"):
        line = line.strip()
        if line.startswith("data: "):
            payload = line[6:]
            if payload == "[DONE]":
                continue
            try:
                events.append(json.loads(payload))
            except json.JSONDecodeError:
                pass
    if not events:
        return None

    text_parts = []
    thinking_parts = []
    tool_uses = []
    usage = None
    stop_reason = None

    for event in events:
        etype = event.get("type", "")
        if etype == "message_start":
            msg = event.get("message", {})
            usage = msg.get("usage", {})
        elif etype == "content_block_start":
            block = event.get("content_block", {})
            if block.get("type") == "tool_use":
                tool_uses.append({
                    "id": block.get("id", "?"),
                    "name": block.get("name", "?"),
                    "input": "",
                })
        elif etype == "content_block_delta":
            delta = event.get("delta", {})
            dtype = delta.get("type", "")
            if dtype == "text_delta":
                text_parts.append(delta.get("text", ""))
            elif dtype == "input_json_delta":
                if tool_uses:
                    tool_uses[-1]["input"] += delta.get("partial_json", "")
            elif dtype == "thinking_delta":
                thinking_parts.append(delta.get("thinking", ""))
        elif etype == "message_delta":
            delta = event.get("delta", {})
            stop_reason = delta.get("stop_reason")
            msg_usage = event.get("usage", {})
            if msg_usage:
                usage = {**(usage or {}), **msg_usage}

    # Parse tool use inputs
    for tu in tool_uses:
        try:
            tu["input"] = json.loads(tu["input"]) if tu["input"] else {}
        except json.JSONDecodeError:
            tu["input"] = tu["input"]

    return {
        "text": "".join(text_parts),
        "thinking": "".join(thinking_parts),
        "tool_uses": tool_uses,
        "stop_reason": stop_reason,
        "usage": usage,
    }

