function switchRawTab(el) {
  const parent = el.parentElement;
  const panelId = el.dataset.panel;
  // Deactivate all tabs in this group
  parent.querySelectorAll('.raw-tab').forEach(t => t.classList.remove('active'));
  el.classList.add('active');
  // Hide all panels that are siblings of this tab group
  const section = parent.parentElement;
  section.querySelectorAll('.raw-panel').forEach(p => p.classList.add('hidden'));
  const panel = document.getElementById(panelId);
  if (panel) panel.classList.remove('hidden');
}

