const perAgent = sp.per_agent || {};
const agentIds = Object.keys(perAgent);

// Group agents by identical prompt hash
const promptGroups = {};
for (const [agentId, info] of Object.entries(perAgent)) {
  const h = info.hash;
  if (!promptGroups[h]) promptGroups[h] = { info, agents: [] };
  promptGroups[h].agents.push(agentId);
