for (const [hash, group] of Object.entries(promptGroups)) {
  const info = group.info;
  const agentNames = group.agents;
  const color = getAgentColor(agentNames[0]);
  const label = agentNames.length === 1
    ? agentNames[0]
    : agentNames.join(', ');
  const sharedNote = agentNames.length > 1
    ? ` <span style="font-size:11px;color:var(--text-dim)">(shared by ${agentNames.length} agents)</span>`
    : '';

  html += `<h3 style="margin:16px 0 8px;color:${color}">${esc(label)}${sharedNote} <span style="color:var(--text-dim);font-size:12px">${fmt(info.length)} chars, hash: ${hash}</span></h3>`;

